diff --git a/llvm/lib/Transforms/IPO/GlobalOpt.cpp b/llvm/lib/Transforms/IPO/GlobalOpt.cpp
index cfba8dcc05b2..c60bd369574b 100644
--- a/llvm/lib/Transforms/IPO/GlobalOpt.cpp
+++ b/llvm/lib/Transforms/IPO/GlobalOpt.cpp
@@ -1038,6 +1038,27 @@ OptimizeGlobalAddressOfAllocation(GlobalVariable *GV, CallInst *CI,
   return NewGV;
 }

+// Check if the global variable has any atomic accesses.
+static bool hasAtomicAccesses(const GlobalVariable *GV) {
+  SmallVector<const Value *, 4> Worklist;
+  Worklist.push_back(GV);
+  while (!Worklist.empty()) {
+    const Value *P = Worklist.pop_back_val();
+    for (const auto *U : P->users()) {
+      if (auto *LI = dyn_cast<LoadInst>(U)) {
+        if (LI->isAtomic())
+          return true;
+      } else if (auto *SI = dyn_cast<StoreInst>(U)) {
+        if (SI->isAtomic())
+          return true;
+      } else if (auto *CE = dyn_cast<ConstantExpr>(U)) {
+        Worklist.push_back(CE);
+      }
+    }
+  }
+  return false;
+}
+
 /// Scan the use-list of GV checking to make sure that there are no complex uses
 /// of GV.  We permit simple things like dereferencing the pointer, but not
 /// storing through the address, unless it is to the specified global.
@@ -1111,7 +1132,11 @@ static bool tryToOptimizeStoreOfAllocationToGlobal(GlobalVariable *GV,
   // been reached).  To do this, we check to see if all uses of the global
   // would trap if the global were null: this proves that they must all
   // happen after the malloc.
-  if (!allUsesOfLoadedValueWillTrapIfNull(GV))
+  // Additionally, we cannot optimize if there are atomic accesses to the global,
+  // as the boolean tracking optimization would create invalid atomic operations
+  // on i1 type (which is not byte-sized).
+  if (!allUsesOfLoadedValueWillTrapIfNull(GV) ||
+      hasAtomicAccesses(GV))
     return false;

   // We can't optimize this if the malloc itself is used in a complex way,

